const results = $.steps.webSearch.response.results || [];
const question = $.input.question;

let sourcesText = '';
results.forEach((r, i) => {
  sourcesText += (i+1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  if (r.publishedDate) sourcesText += '   Published: ' + r.publishedDate + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1200) + '\n\n';
});

return { sourcesText, sourceCount: results.length, topSources: results.slice(0, 3).map(r => r.title || r.url) };

const prompt = `You are a knowledgeable AI assistant. Answer the following question using the web search results provided. Be thorough, accurate, and cite your sources by number.

QUESTION: ${$.input.question}

WEB SEARCH RESULTS (${$.steps.compileSources.output.sourceCount} sources found):
${$.steps.compileSources.output.sourcesText}

INSTRUCTIONS:
- Synthesize information from multiple sources into a coherent, comprehensive answer
- Cite sources by their number, e.g. [1], [2]
- If sources conflict, note the disagreement
- If the sources don't adequately answer the question, say so
- Use Slack mrkdwn formatting: *bold*, _italic_, > for quotes, numbered lists
- Slack mrkdwn rules: use *bold* (NOT **bold**). No markdown tables. No # headings.

Return ONLY valid JSON with this structure:
{
  "answer": "<comprehensive answer using Slack mrkdwn>",
  "confidence": "high|medium|low",
  "keyPoints": ["<point1>", "<point2>"],
  "sourcesUsed": [<source numbers used>]
}`;

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', keyPoints: [], sourcesUsed: [] }; }

const ai = $.steps.parseAI.output || {};
const question = $.input.question;
const sourceCount = $.steps.compileSources.output.sourceCount;
const topSources = $.steps.compileSources.output.topSources || [];

const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Agent Chat Response' } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });
blocks.push({ type: 'divider' });

if (ai.keyPoints && ai.keyPoints.length > 0) {
  let kpText = '*Key Points:*\n';
  ai.keyPoints.forEach((p, i) => { kpText += (i+1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kpText } });
  blocks.push({ type: 'divider' });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' Confidence: *' + (ai.confidence || 'medium') + '* | Sources analyzed: *' + sourceCount + '* | Sources cited: *' + ((ai.sourcesUsed || []).length) + '*' }] });

const fallback = 'AI Agent answer to: ' + question;

return { blocks, fallback };
